#define LIMIT -999

#ifdef RD_WG_SIZE_0_0
    #define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
    #define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
    #define BLOCK_SIZE RD_WG_SIZE
#else
    #define BLOCK_SIZE 16
#endif

int maximum(int a, int b, int c) {
    int k;
    if (a <= b)
        k = b;
    else
        k = a;

    if (k <= c)
        return c;
    else
        return k;
}

__kernel void needle_kernel1(__global int* referrence,
                             __global int* matrix_cuda,
                             __global int* output,
                             int cols,
                             int penalty,
                             int i,
                             int block_width,
                             int worksize,
                             int offset_r,
                             int offset_c) {
    int bx = get_block_id(0);
    int tx = get_local_id(0);

    int b_index_x = bx;
    int b_index_y = i - 1 - bx;

    int base_index = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;
    int index = base_index + tx + (cols + 1);
    int index_n = base_index + tx + 1;
    int index_w = base_index + cols;
    int index_nw = base_index;

    // Use local memory with explicit size
    __local int temp[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    __local int ref[BLOCK_SIZE * BLOCK_SIZE];

    // Load reference data
    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        ref[ty * BLOCK_SIZE + tx] = referrence[index + cols * ty];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    // Load boundary values
    if (tx == 0)
        temp[0] = matrix_cuda[index_nw];
    barrier(CLK_LOCAL_MEM_FENCE);

    temp[(tx + 1) * (BLOCK_SIZE + 1)] = matrix_cuda[index_w + cols * tx];
    barrier(CLK_LOCAL_MEM_FENCE);

    temp[tx + 1] = matrix_cuda[index_n];
    barrier(CLK_LOCAL_MEM_FENCE);

    // First diagonal pass
    for (int m = 0; m < BLOCK_SIZE; m++) {
        if (tx <= m) {
            int t_index_x = tx + 1;
            int t_index_y = m - tx + 1;

            int val_nw = temp[(t_index_y - 1) * (BLOCK_SIZE + 1) + (t_index_x - 1)];
            int val_w = temp[(t_index_y) * (BLOCK_SIZE + 1) + (t_index_x - 1)];
            int val_n = temp[(t_index_y - 1) * (BLOCK_SIZE + 1) + (t_index_x)];
            int ref_val = ref[(t_index_y - 1) * BLOCK_SIZE + (t_index_x - 1)];

            temp[t_index_y * (BLOCK_SIZE + 1) + t_index_x] = maximum(val_nw + ref_val,
                                                                     val_w - penalty,
                                                                     val_n - penalty);
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Second diagonal pass
    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
        if (tx <= m) {
            int t_index_x = tx + BLOCK_SIZE - m;
            int t_index_y = BLOCK_SIZE - tx;

            int val_nw = temp[(t_index_y - 1) * (BLOCK_SIZE + 1) + (t_index_x - 1)];
            int val_w = temp[(t_index_y) * (BLOCK_SIZE + 1) + (t_index_x - 1)];
            int val_n = temp[(t_index_y - 1) * (BLOCK_SIZE + 1) + (t_index_x)];
            int ref_val = ref[(t_index_y - 1) * BLOCK_SIZE + (t_index_x - 1)];

            temp[t_index_y * (BLOCK_SIZE + 1) + t_index_x] = maximum(val_nw + ref_val,
                                                                     val_w - penalty,
                                                                     val_n - penalty);
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Write results
    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        output[index + ty * cols] = temp[(ty + 1) * (BLOCK_SIZE + 1) + (tx + 1)];
    }
}

